-- Corrosive Armor Tracker - UI Controller\n-- Handles visual display and sound alerts\n\nCorrosiveArmorTracker.UI = {}\n\n-- Control references\nlocal warningContainer = nil\nlocal warningLabel = nil\n\n-- Initialize UI module and cache control references\nfunction CorrosiveArmorTracker.UI.Initialize()\n    -- Get references to UI controls created in XML\n    warningContainer = _G[\"CorrosiveArmorWarningContainer\"]\n    warningLabel = _G[\"CorrosiveArmorWarningLabel\"]\n    \n    if warningContainer then\n        warningContainer:SetHidden(true)\n    end\n    \n    if warningLabel then\n        warningLabel:SetText(\"\u26a0 CORROSIVE ARMOR ACTIVE \u26a0\")\n    end\nend\n\n-- Show warning when hovering unit with Corrosive Armor\nfunction CorrosiveArmorTracker.UI.ShowWarning(unitName)\n    if not warningContainer then return end\n    \n    -- Update label with unit name\n    if warningLabel then\n        warningLabel:SetText(\"\u26a0 CORROSIVE ARMOR ACTIVE \u26a0\\n\" .. unitName)\n    end\n    \n    -- Show the warning container\n    warningContainer:SetHidden(false)\n    \n    -- Play sound alert if enabled\n    if CorrosiveArmorTrackerSavedVars and CorrosiveArmorTrackerSavedVars.enabledSound then\n        PlaySound(SOUNDS.DUEL_START)\n    end\nend\n\n-- Hide warning when not hovering tracked unit\nfunction CorrosiveArmorTracker.UI.HideWarning()\n    if not warningContainer then return end\n    warningContainer:SetHidden(true)\nend